const body = $input.item.json.body || {};
const text = String(body.content || '').trim();
let mode = String(body.mode || 'chat').toLowerCase();

const history = Array.isArray(body.history) ? body.history : [];
const historyEntries = history
  .slice(-20)
  .map((h) => ({
    sender: String((h && h.sender) || ''),
    text: String((h && h.text) || ''),
    timestamp: String((h && h.timestamp) || ''),
  }));

const historyText = historyEntries
  .map((h) => `${h.sender || 'unknown'}: ${h.text}`)
  .join('\n');

const cleanupPath = (raw) => {
  let p = String(raw || '').replace(/\\/g, '/').trim();
  p = p.replace(/^[\s"'`]+|[\s"'`]+$/g, '');
  p = p.replace(/[\]\)\}]+$/g, '');
  p = p.replace(/[.,;:!?]+$/g, '');
  return p;
};

const pathRegex = /([A-Za-z]:[\\/][^\n\r]+)/g;

const extractPathCandidates = (msg) => {
  const source = String(msg || '');
  const out = [];

  const targetLine = source.match(/Target file path:\s*([^\n\r]+)/i);
  if (targetLine && targetLine[1]) out.push(targetLine[1]);

  const commonInline = [...source.matchAll(/(?:file\s+to|path\s*:|at)\s*([A-Za-z]:[\\/][^\n\r]+)/gi)];
  for (const m of commonInline) {
    if (m && m[1]) out.push(m[1]);
  }

  const generic = [...source.matchAll(pathRegex)];
  for (const m of generic) {
    if (m && m[1]) out.push(m[1]);
  }

  return out;
};

const extractLastPath = (entries) => {
  for (let i = entries.length - 1; i >= 0; i--) {
    const msg = entries[i].text || '';
    const matches = extractPathCandidates(msg);
    for (let j = matches.length - 1; j >= 0; j--) {
      const p = cleanupPath(matches[j] || '');
      if (p) return p;
    }
  }
  return '';
};

const fileIntentRegex = /\b(write|put|create|save|append|update|udpate|updte|updat|udate|edit|modify|add|make|build|generate|include|insert|format|transform|adjust|read|open|show|list)\b[\s\S]*\b(file|txt|text|document|note|folder|directory|files?)\b/i;

const extractLastUserFileCommand = (entries) => {
  for (let i = entries.length - 1; i >= 0; i--) {
    const e = entries[i];
    if ((e.sender || '').toLowerCase() !== 'user') continue;
    if (fileIntentRegex.test(e.text || '')) return String(e.text || '').trim();
  }
  return '';
};

const readTextFileSafe = (absolutePath) => {
  try {
    const fs = require('fs');
    const p = cleanupPath(absolutePath);
    if (!p || !fs.existsSync(p)) return '';
    return String(fs.readFileSync(p, 'utf8') || '').slice(0, 5000);
  } catch (e) {
    return '';
  }
};

const lastFilePath = cleanupPath(extractLastPath(historyEntries));
const lastUserFileCommand = extractLastUserFileCommand(historyEntries);

const shortFollowUp = /^\s*(do it|you do it|make it|please do it|i need you to make it|i need you top make it|just do it)\s*[.!?]*\s*$/i.test(text);

const lowerText = text.toLowerCase();
const hasContextPronoun = /\b(it|this|that|same)\b/.test(lowerText);
const hasWriteVerb = /\b(write|put|add|append|update|udpate|updte|updat|udate|edit|modify|change|replace|rewrite|create|make|include|insert|format|transform|adjust)\b/.test(lowerText);
const hasLineIntent = /\b(?:\d+(?:st|nd|rd|th)?[a-z]*|first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)\s+line\b/.test(lowerText);
const hasLatestFileReference = /\b(?:latest|last|previous|current)\s+(?:txt|text|file|document)\b/.test(lowerText);

let normalizedContent = text;

if (shortFollowUp && lastUserFileCommand) {
  normalizedContent = lastUserFileCommand;
}

const needsContextBinding = !!lastFilePath && (
  /\b(that|this|same)\s+file\b/.test(lowerText) ||
  /\b(?:in|into)\s+it\b/.test(lowerText) ||
  hasLatestFileReference ||
  (hasContextPronoun && hasWriteVerb) ||
  hasLineIntent
);

if (needsContextBinding) {
  if (!/Target file path:/i.test(normalizedContent)) {
    normalizedContent += `\n\nTarget file path: ${lastFilePath}`;
  }
  const currentFileContent = readTextFileSafe(lastFilePath);
  if (currentFileContent) {
    normalizedContent += `\n\nCurrent file content:\n${currentFileContent}`;
  }
}

if (mode === 'chat') {
  const lower = normalizedContent.toLowerCase();

  const toolIntent = [
    /\b(write|put|create|save|append|update|udpate|updte|updat|udate|edit|modify|add|make|build|generate|include|insert|format|transform|adjust)\b.*\b(file|txt|text|document|note)\b/,
    /\b(read|open|show)\b.*\b(file|txt|text|document|note)\b/,
    /\b(list|show)\b.*\b(directory|folder|files?)\b/,
    /\b(make|create)\b.*\b(folder|directory)\b/,
    /\b(that|this|same)\s+file\b/,
    /\b(?:in|into)\s+it\b/,
    /\b(?:latest|last|previous|current)\s+(?:txt|text|file|document)\b/,
    /\bmake\s+me\b.*\b(txt|file)\b/,
    /\bhello\s+world\b.*\b(txt|file)\b/,
  ].some((r) => r.test(lower));

  const contextualFileFollowUp = !!lastFilePath && (
    ((/\b(it|this|that|same)\b/.test(lower) || /\b(?:in|into)\s+it\b/.test(lower) || hasLatestFileReference) && /\b(write|put|add|append|update|udpate|updte|updat|udate|edit|modify|change|replace|rewrite|include|insert|format|transform|adjust)\b/.test(lower)) ||
    /\b(?:\d+(?:st|nd|rd|th)?[a-z]*|first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)\s+line\b/.test(lower)
  );

  if (toolIntent || shortFollowUp || contextualFileFollowUp) {
    mode = 'tool';
  }
}

return { json: { mode, content: normalizedContent, historyText, lastFilePath, lastUserFileCommand } };

const response = String($input.item.json.response || '');
const plannerTier = String($input.item.json.plannerTier || 'small').toLowerCase();
const baseDir = 'C:/Users/Martin/.n8n-files/Axiom_Files';
const originalCommand = String($node["Extract Input"].json.content || '');
const lastFilePath = String($node["Extract Input"].json.lastFilePath || '');
const lastUserFileCommand = String($node["Extract Input"].json.lastUserFileCommand || '');
const lowerCommand = originalCommand.toLowerCase();

const cleanupPath = (raw) => {
  let p = String(raw || '').replace(/\\/g, '/').trim();
  p = p.replace(/^[\s"'`]+|[\s"'`]+$/g, '');
  p = p.replace(/[\]\)\}]+$/g, '');
  p = p.replace(/[.,;:!?]+$/g, '');
  return p;
};

const toForwardSlashes = (v) => cleanupPath(v);

const sanitizeName = (name) => {
  let n = String(name || '').trim();
  if (!n) return '';
  n = n.replace(/[<>:"/\\|?*]/g, ' ');
  n = n.replace(/\s+/g, '_');
  n = n.replace(/^_+|_+$/g, '');
  n = n.replace(/[^A-Za-z0-9._-]/g, '');
  if (!n) return '';
  if (!/\.[A-Za-z0-9]+$/.test(n)) n += '.txt';
  return n;
};

const sanitizePath = (input, actionType) => {
  let p = toForwardSlashes(input);
  if (!p) {
    if (actionType === 'write_file') return `${baseDir}/helloWorld.txt`;
    return baseDir;
  }
  if (/^[a-zA-Z]:/.test(p)) {
    if (p.toLowerCase().startsWith(baseDir.toLowerCase())) return p;
    const name = sanitizeName(p.split('/').filter(Boolean).pop() || 'file.txt') || 'file.txt';
    return `${baseDir}/${name}`;
  }
  const maybeName = sanitizeName(p.replace(/^\/+/, ''));
  if (actionType === 'write_file' && maybeName) return `${baseDir}/${maybeName}`;
  return `${baseDir}/${p.replace(/^\/+/, '')}`;
};

const parseJsonPayload = (text) => {
  const t = String(text || '').trim();
  if (!t) return null;

  const candidates = [t];
  const unfenced = t.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  if (unfenced && unfenced !== t) candidates.push(unfenced);

  const m = unfenced.match(/\{[\s\S]*\}/);
  if (m) candidates.push(m[0]);

  for (const c of candidates) {
    try {
      return JSON.parse(c);
    } catch (e) {}
  }
  return null;
};

const ordinalMap = { first:1, second:2, third:3, fourth:4, fifth:5, sixth:6, seventh:7, eighth:8, ninth:9, tenth:10 };
const wordToNum = { one:1, two:2, three:3, four:4, five:5, six:6, seven:7, eight:8, nine:9, ten:10 };

const parseLineNumber = (value) => {
  const t = String(value || '').toLowerCase().trim();
  if (ordinalMap[t]) return ordinalMap[t];
  const m = t.match(/^(\d+)(?:st|nd|rd|th)?[a-z]*$/);
  if (!m) return null;
  const n = Number(m[1]);
  if (!Number.isFinite(n) || n < 1) return null;
  return n;
};

const extractQuotedText = (text) => {
  const dq = String(text || '').match(/"([^"]+)"/);
  if (dq) return dq[1];
  const sq = String(text || '').match(/'([^']+)'/);
  if (sq) return sq[1];
  return '';
};

const extractFileNameHint = (text) => {
  const src = String(text || '');
  const patterns = [
    /\b(?:called|named|name\s+it)\s+([A-Za-z0-9 _.-]{1,80})\b/i,
    /\bfile\s+name\s*(?::|is)?\s+([A-Za-z0-9 _.-]{1,80})\b/i,
    /\bfilename\s*(?::|is)?\s+([A-Za-z0-9 _.-]{1,80})\b/i,
  ];
  for (const re of patterns) {
    const m = src.match(re);
    if (m && m[1]) {
      const name = sanitizeName(m[1]);
      if (name) return name;
    }
  }
  return '';
};

const extractCreatePayload = (text) => {
  const source = String(text || '');
  const quoted = extractQuotedText(source);
  if (quoted) return quoted;

  const withText = source.match(/\bwith\s+text\s+(.+?)(?:\s*(?:,|\.)?\s*(?:make\s+sure|call(?:ed)?|named|name\s+it|file\s+name|filename)\b|$)/i);
  if (withText) return withText[1].trim();

  const textIs = source.match(/\btext\s*(?::|is)?\s+(.+?)(?:\s*(?:,|\.)?\s*(?:make\s+sure|call(?:ed)?|named|name\s+it|file\s+name|filename)\b|$)/i);
  if (textIs) return textIs[1].trim();

  const putInto = source.match(/\b(?:write|put|save|append|add|make)\s+(.+?)\s+(?:to|into)\s+(?:the\s+)?(?:file|txt|text|document|[A-Za-z0-9._-]+\.[A-Za-z0-9._-]+)/i);
  if (putInto) return putInto[1].trim();

  const m1 = source.match(/\b(?:create|make)(?:\s+me)?\s+(.+?)\s+in\s+(?:a\s+)?txt\s+file\b/i);
  if (m1) return m1[1].trim();

  const m2 = source.match(/\b(?:create|make)(?:\s+me)?\s+(.+?)\s+file\b/i);
  if (m2) return m2[1].trim();

  if (/hello\s+world/i.test(source)) return 'hello world';
  return '';
};

const parseRequestedCount = (text) => {
  const lower = String(text || '').toLowerCase();
  const m = lower.match(/\b(\d+|one|two|three|four|five|six|seven|eight|nine|ten)\b\s+(?:biggest|largest|top)?\s*\w*\s*capitals?/);
  if (!m) return null;
  const token = m[1];
  let n = Number(token);
  if (!Number.isFinite(n)) n = wordToNum[token] || null;
  if (!n || n < 1) return null;
  return n;
};

const parseNthUpperRule = (textLower) => {
  const explicit = textLower.match(/(?:every|each)\s+(\d+)(?:st|nd|rd|th)?\s+letter[^\n\r]*capit/);
  if (explicit) {
    const n = Number(explicit[1]);
    if (Number.isFinite(n) && n > 1) return n;
  }
  if (/(?:every|each)\s+(second|2nd|senond|secnd|seconf|secong)\s+letter[^\n\r]*capit/.test(textLower)) return 2;
  if (/(?:every|each)\s+(third|3rd|tird)\s+letter[^\n\r]*capit/.test(textLower)) return 3;
  return null;
};

const applyNthUpper = (text, n) => {
  let idx = 0;
  return Array.from(String(text || '')).map((ch) => {
    if (!/[a-zA-Z]/.test(ch)) return ch;
    idx += 1;
    return (idx % n === 0) ? ch.toUpperCase() : ch.toLowerCase();
  }).join('');
};

const inferTopCapitalsContent = (cmd) => {
  const lower = String(cmd || '').toLowerCase();
  const count = parseRequestedCount(lower);
  if (!count || !/\bcapitals?\b/.test(lower)) return '';

  const ranked = ['Tokyo', 'Delhi', 'Beijing', 'Cairo', 'Moscow', 'London', 'Paris', 'Madrid'];
  const chosen = ranked.slice(0, count);
  const spaced = /\b(each|every)\s+(two|2)\s+lines?\b/.test(lower) || /\btwo\s+lines?\b/.test(lower) || /\bover\s+next\b/.test(lower);
  return chosen.join(spaced ? '\n\n' : '\n');
};

const resolveKnowledgePhrase = (text) => {
  const t = String(text || '').trim();
  const lower = t.toLowerCase();
  if (/\bslovakia\b/.test(lower) && /\bcapital\b/.test(lower)) return 'Bratislava';
  return t;
};

const normalizeLineEdits = (raw) => {
  if (!Array.isArray(raw)) return [];
  const out = [];
  for (const item of raw) {
    if (!item || typeof item !== 'object') continue;
    const line = parseLineNumber(item.line);
    if (!line) continue;
    let text = item.text === undefined ? '' : String(item.text).trim();
    if (!text) continue;
    text = resolveKnowledgePhrase(text);
    out.push({ line, text });
  }
  return out;
};

const extractLineEditsFromCommand = (text) => {
  const out = [];
  const re = /(?:add|put|set|write|change|make|update|udpate|updte|updat|udate)\s+(.+?)\s+(?:on|to|at)\s+(?:the\s+)?(\d+(?:st|nd|rd|th)?[a-z]*|first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)\s+line/gi;
  const matches = [...String(text || '').matchAll(re)];
  for (const m of matches) {
    const line = parseLineNumber(m[2]);
    if (!line) continue;
    let value = String(m[1] || '').trim();
    value = value.replace(/^\s*(?:is|to|as|should\s+be|should\s+say|it\s+is|it\s+says?|says?)\s*/i, '');
    value = value.replace(/^['"]|['"]$/g, '').trim();
    value = resolveKnowledgePhrase(value);
    if (!value) continue;
    out.push({ line, text: value });
  }
  return out;
};

const applyLineEdits = (existingContent, edits) => {
  let lines = String(existingContent || '').split(/\r?\n/);
  if (lines.length === 1 && lines[0] === '') lines = [];
  const maxLine = Math.max(...edits.map((e) => e.line));
  while (lines.length < maxLine) lines.push('');
  for (const e of edits) lines[e.line - 1] = e.text;
  return lines.join('\n');
};

const extractInjectedCurrentContent = (cmd) => {
  const m = String(cmd || '').match(/Current file content:\n([\s\S]*)$/i);
  return m ? String(m[1] || '') : '';
};

const isSpaceAfterEachLetterIntent = (cmdLower) => {
  return /\b(?:space|spacing)\b.*\b(?:after|between)\b.*\b(?:each|every)\b.*\b(?:letter|character|char)\b/.test(cmdLower) ||
    /\binclude\s+space\s+after\s+each\s+(?:letter|character|char)\b/.test(cmdLower) ||
    /\bspace\s+out\s+(?:the\s+)?(?:letters|text)\b/.test(cmdLower);
};

const spaceOutLetters = (txt) => {
  const lines = String(txt || '').split(/\r?\n/);
  return lines.map((line) => {
    let out = '';
    for (const ch of line) {
      if (ch === ' ') out += '  ';
      else out += ch + ' ';
    }
    return out.trimEnd();
  }).join('\n');
};


const escapeRegExp = (str) => String(str || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const extractReplaceSpec = (text) => {
  const src = String(text || '').trim();
  const m1 = src.match(/\breplace\s+"([^"]+)"\s+with\s+"([^"]+)"/i);
  if (m1) return { from: m1[1], to: m1[2], caseSensitive: false };
  const m2 = src.match(/\breplace\s+'([^']+)'\s+with\s+'([^']+)'/i);
  if (m2) return { from: m2[1], to: m2[2], caseSensitive: false };
  const m3 = src.match(/\breplace\s+([^\n\r]+?)\s+with\s+([^\n\r]+?)\s*$/i);
  if (m3) return {
    from: String(m3[1] || '').trim().replace(/^['"]|['"]$/g, ''),
    to: String(m3[2] || '').trim().replace(/^['"]|['"]$/g, ''),
    caseSensitive: false,
  };
  return null;
};

const applyReplace = (text, spec) => {
  const input = String(text || '');
  if (!spec || !spec.from) return input;
  const re = new RegExp(escapeRegExp(spec.from), spec.caseSensitive ? 'g' : 'gi');
  return input.replace(re, String(spec.to || ''));
};

const extractCommandPath = (text) => {
  const t = String(text || '');
  const direct = t.match(/([A-Za-z]:[\\/][^\n\r]+)/);
  if (direct && direct[1]) return cleanupPath(direct[1]);
  return '';
};

const inferActionFromCommand = (text, contextPath) => {
  const lower = String(text || '').toLowerCase();
  const hasRead = /\b(read|open|show)\b/.test(lower) && /\b(file|txt|text|document|note)\b/.test(lower);
  const hasList = /\b(list|show)\b/.test(lower) && /\b(directory|folder|files?)\b/.test(lower);
  const hasWrite = /\b(write|put|create|save|append|update|udpate|updte|updat|udate|edit|modify|add|make|build|generate|include|insert|format|transform|adjust|rewrite|change|replace)\b/.test(lower) &&
    (/\b(file|txt|text|document|note)\b/.test(lower) || /\b(it|this|that|same|latest|last|previous|current)\b/.test(lower));

  if (hasRead) return 'read_file';
  if (hasList) return 'list_directory';
  if (hasWrite) return 'write_file';

  // Contextual write follow-up
  if (contextPath && /\b(it|this|that|same|latest|last|previous|current)\b/.test(lower) &&
      /\b(add|append|update|edit|modify|change|replace|rewrite|include|insert|format|transform|adjust|write|put)\b/.test(lower)) {
    return 'write_file';
  }

  return '';
};

const parsed = parseJsonPayload(response) || {};
const modelConfidence = Number(parsed.confidence);

const allowedActions = ['write_file', 'read_file', 'list_directory'];
const plannerAction = allowedActions.includes(String(parsed.action || '').toLowerCase()) ? String(parsed.action).toLowerCase() : '';
const inferredAction = inferActionFromCommand(originalCommand, lastFilePath);

let action = plannerAction || inferredAction || 'error';
if (inferredAction && plannerAction && inferredAction !== plannerAction) {
  // Deterministic parser wins when there's disagreement
  action = inferredAction;
}

const contextRef = /\b(this|that|same|latest|last|previous|current)\b/.test(lowerCommand) || /\b(?:in|into)\s+it\b/.test(lowerCommand);
const explicitPathFromCommand = extractCommandPath(originalCommand);
const fileNameHint = extractFileNameHint(originalCommand);
const rawPath = cleanupPath(parsed.path || parsed.filePath || parsed.filename || '');
const hasExplicitPathInCommand = !!explicitPathFromCommand || /\b[A-Za-z0-9 _.-]+\.(?:txt|text|md|json|csv|log)\b/i.test(originalCommand);

let chosenPath = '';
if (explicitPathFromCommand) {
  chosenPath = explicitPathFromCommand;
} else if (lastFilePath && contextRef && !hasExplicitPathInCommand) {
  chosenPath = lastFilePath;
} else if (action === 'write_file' && fileNameHint && !contextRef) {
  chosenPath = fileNameHint;
} else if (rawPath) {
  chosenPath = rawPath;
} else if (action === 'write_file') {
  chosenPath = lastFilePath || 'helloWorld.txt';
} else {
  chosenPath = lastFilePath || baseDir;
}

const fullPath = sanitizePath(chosenPath, action);

let append = parsed.append !== undefined ? !!parsed.append : (String(parsed.writeMode || '').toLowerCase() === 'append');
const commandHasLineIntent = /\b(?:\d+(?:st|nd|rd|th)?[a-z]*|first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)\s+line\b/.test(lowerCommand);
const plannerWriteMode = String(parsed.writeMode || '').toLowerCase();
let lineEdits = normalizeLineEdits(parsed.lineEdits);
if (lineEdits.length && !commandHasLineIntent && plannerWriteMode !== 'line_edit') {
  lineEdits = [];
}
const commandLineEdits = extractLineEditsFromCommand(originalCommand);
if (commandLineEdits.length) lineEdits = commandLineEdits;

let content = parsed.content === undefined ? '' : String(parsed.content);
if (!content && parsed.text !== undefined) content = String(parsed.text);

const injectedCurrent = extractInjectedCurrentContent(originalCommand);
const spaceIntent = isSpaceAfterEachLetterIntent(lowerCommand);
const nthRule = parseNthUpperRule(lowerCommand);
const capitalsIntent = /\bcapitals?\b/.test(lowerCommand) && /\b(write|put|add)\b/.test(lowerCommand);
const replaceSpec = extractReplaceSpec(originalCommand);
const transformVerb = /\b(update|udpate|updte|updat|udate|edit|modify|change|replace|rewrite|transform|format|adjust)\b/.test(lowerCommand);

const deterministicTransform = (() => {
  if (spaceIntent && (contextRef || !!lastFilePath)) {
    return { type: 'space_letters' };
  }
  if (replaceSpec && (contextRef || transformVerb || !!lastFilePath)) {
    return { type: 'replace_text', ...replaceSpec };
  }
  if (commandLineEdits.length > 0 && (contextRef || transformVerb || !!lastFilePath)) {
    return { type: 'line_edit', lineEdits: commandLineEdits };
  }
  if (nthRule && (contextRef || transformVerb)) {
    return { type: 'uppercase_nth', n: nthRule };
  }
  return null;
})();

const missingTransformTarget = !!deterministicTransform && !explicitPathFromCommand && !rawPath && !lastFilePath;
if (missingTransformTarget) {
  action = 'error';
}

if (deterministicTransform && action !== 'error') {
  action = 'read_file';
  append = false;
  content = '';
  lineEdits = [];
}

if (action === 'write_file') {
  if (!content && /\b(create|make|write)\b/.test(lowerCommand)) {
    content = extractCreatePayload(originalCommand);
  }

  if (!content && lastUserFileCommand && /\b(create|make|write)\b/.test(lastUserFileCommand.toLowerCase())) {
    content = extractCreatePayload(lastUserFileCommand);
  }

  if (capitalsIntent) {
    const capitals = inferTopCapitalsContent(originalCommand);
    if (capitals) {
      content = capitals;
      append = false;
    }
  }

  if (nthRule && content) {
    content = applyNthUpper(content, nthRule);
  }

  content = String(content || '').trimEnd();
}

if (action === 'error' && missingTransformTarget) {
  return {
    json: {
      action: 'error',
      message: 'Transform requested but no target file was resolved from context',
      content: '',
      fullPath: baseDir,
      path: baseDir,
      isExternal: false,
      append: false,
      confidence: 0,
      modelConfidence: Number.isFinite(modelConfidence) ? modelConfidence : null,
      parserTier: plannerTier,
      confidenceBreakdown: {},
      postReadTransform: deterministicTransform || undefined,
    },
  };
}

if (action === 'write_file' && !String(content || '').trim()) {
  return {
    json: {
      action: 'error',
      message: 'Write request missing content after normalization',
      content: '',
      fullPath,
      path: fullPath,
      isExternal: false,
      append: false,
      confidence: 0,
      modelConfidence: Number.isFinite(modelConfidence) ? modelConfidence : null,
      parserTier: plannerTier,
      confidenceBreakdown: {},
    },
  };
}

if (!allowedActions.includes(action)) {
  return {
    json: {
      action: 'error',
      message: 'Unable to resolve valid action',
      content: '',
      fullPath: baseDir,
      path: baseDir,
      isExternal: false,
      append: false,
      confidence: 0,
      modelConfidence: Number.isFinite(modelConfidence) ? modelConfidence : null,
      parserTier: plannerTier,
      confidenceBreakdown: {},
    },
  };
}

const inferActionMatch = inferredAction ? inferredAction === action : true;
const sanePath = !!fullPath && (fullPath.toLowerCase().startsWith(baseDir.toLowerCase()) || /^[A-Za-z]:\//.test(fullPath));
const hasSpecificFilePath = !!fullPath && !String(fullPath || '').match(/\/Axiom_Files\/?$/);
const requiredFields = action === 'write_file'
  ? (String(content || '').trim().length > 0 && !!fullPath)
  : (action === 'read_file' && deterministicTransform ? hasSpecificFilePath : !!fullPath);
const needsContextBinding = contextRef && !hasExplicitPathInCommand;
const contextBindingSucceeded = !needsContextBinding || (lastFilePath && sanitizePath(lastFilePath, action).toLowerCase() === fullPath.toLowerCase());

let contentSanity = true;
if (action === 'write_file') {
  const c = String(content || '');
  if (!c.trim()) contentSanity = false;
} else if (action === 'read_file' && deterministicTransform) {
  if (deterministicTransform.type === 'line_edit') {
    contentSanity = Array.isArray(deterministicTransform.lineEdits) && deterministicTransform.lineEdits.length > 0;
  } else if (deterministicTransform.type === 'replace_text') {
    contentSanity = !!String(deterministicTransform.from || '').trim();
  } else if (deterministicTransform.type === 'uppercase_nth') {
    const n = Number(deterministicTransform.n || 0);
    contentSanity = Number.isFinite(n) && n > 1;
  }
}

let deterministicConfidence = 0;
const breakdown = {};
if (allowedActions.includes(action)) { deterministicConfidence += 0.25; breakdown.validAction = 0.25; }
if (sanePath) { deterministicConfidence += 0.20; breakdown.sanePath = 0.20; }
if (requiredFields) { deterministicConfidence += 0.20; breakdown.requiredFields = 0.20; }
if (inferActionMatch) { deterministicConfidence += 0.15; breakdown.intentMatch = 0.15; }
if (contextBindingSucceeded) { deterministicConfidence += 0.10; breakdown.contextBinding = 0.10; }
if (contentSanity) { deterministicConfidence += 0.10; breakdown.contentSanity = 0.10; }

deterministicConfidence = Number(deterministicConfidence.toFixed(2));

return {
  json: {
    action,
    content: action === 'write_file' ? String(content || '') : '',
    fullPath,
    path: fullPath,
    isExternal: false,
    append: action === 'write_file' ? append : false,
    confidence: deterministicConfidence,
    modelConfidence: Number.isFinite(modelConfidence) ? modelConfidence : null,
    parserTier: plannerTier,
    confidenceBreakdown: breakdown,
    lineEdits: lineEdits.length ? lineEdits : undefined,
    postReadTransform: deterministicTransform || undefined,
  },
};

const text = String($json.content ?? '');
const fileName = String(($json.fullPath || 'output.txt').split('/').pop() || 'output.txt');

return {
  json: $json,
  binary: {
    content: {
      data: Buffer.from(text, 'utf8').toString('base64'),
      mimeType: 'text/plain',
      fileName,
    },
  },
};

let content = '';
try {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  content = buffer.toString('utf8');
} catch (e) {
  content = '';
}
if (!content && typeof $json.data === 'string') content = String($json.data);
const fileLabel = $json.fileName ? ` (${String($json.fileName)})` : '';
if (!content) {
  return { json: { response: `Unable to read file contents${fileLabel}.` } };
}
return { json: { response: `File Contents${fileLabel}:\n\n${content}` } };

const content = String($json.content || '');
const lower = content.toLowerCase();

const evalSummary = {
  hasFollowUpRef: /\b(it|this|that|same|latest|last|previous|current)\b/.test(lower),
  hasActionVerb: /\b(write|put|add|append|update|edit|modify|change|replace|rewrite|read|open|list|create|make|include|insert|format|transform|adjust)\b/.test(lower),
  hasExplicitPath: /[A-Za-z]:[\\/]/.test(content),
  mentionsFile: /\b(file|txt|text|document|folder|directory)\b/.test(lower),
  modeBeforeRouter: String($json.mode || ''),
};

return {
  json: {
    ...$json,
    inputEvaluation: evalSummary,
  },
};

const originalCommand = String($node['Extract Input'].json.content || '');
const lowerCommand = originalCommand.toLowerCase();
const fullPath = String($json.fullPath || $json.fileName || $json.path || '').replace(/\\/g, '/');
const plannedContent = String($json.content ?? '');
const action = String($json.action || '');

const out = {
  ...$json,
  verification: {
    ok: true,
    reason: 'ok',
    checkedPath: fullPath,
    mode: action || 'unknown',
    verifiedBy: 'plan',
  },
};

if (action === 'write_file') {
  if (!fullPath) {
    out.verification = { ok: false, reason: 'Missing target file path', checkedPath: fullPath, mode: 'write', verifiedBy: 'plan' };
    return { json: out };
  }

  if (!plannedContent.trim()) {
    out.verification = { ok: false, reason: 'Write plan has empty content', checkedPath: fullPath, mode: 'write', verifiedBy: 'plan' };
    return { json: out };
  }

  const isSpaceIntent = /\b(?:space|spacing)\b.*\b(?:after|between)\b.*\b(?:each|every)\b.*\b(?:letter|character|char)\b/.test(lowerCommand)
    || /\binclude\s+space\s+after\s+each\s+(?:letter|character|char)\b/.test(lowerCommand)
    || /\bspace\s+out\s+(?:the\s+)?(?:letters|text)\b/.test(lowerCommand);

  if (isSpaceIntent) {
    const letters = (plannedContent.match(/[A-Za-z]/g) || []).length;
    const spaced = (plannedContent.match(/[A-Za-z] /g) || []).length;
    const ratio = letters > 0 ? (spaced / letters) : 0;
    const ok = letters > 0 && ratio >= 0.85;
    out.verification = {
      ok,
      reason: ok ? 'ok' : `Planned content does not apply space-after-each-letter (ratio ${ratio.toFixed(2)})`,
      checkedPath: fullPath,
      mode: 'write',
      verifiedBy: 'plan',
      ratio,
    };
    return { json: out };
  }
}

return { json: out };

const response = String($json.response || '').trim();
if (!response) {
  return { json: { ...$json, response: 'Workflow completed, but no response payload was generated.' } };
}
return { json: $json };

const plan = $node['Parse JSON'].json || {};
const transform = plan.postReadTransform || $json.postReadTransform;
const fullPath = String(plan.fullPath || plan.path || $json.fullPath || '').replace(/\\/g, '/');

if (!transform || !transform.type) {
  return { json: { action: 'error', fullPath, path: fullPath, message: 'No deterministic transform plan available.' } };
}

let inputText = '';
try {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  inputText = buffer.toString('utf8');
} catch (e) {
  inputText = '';
}
if (!inputText && typeof $json.data === 'string') {
  inputText = String($json.data);
}
if (!inputText.length) {
  return {
    json: {
      action: 'error',
      fullPath,
      path: fullPath,
      message: `Could not load file content for transform at ${fullPath || 'target file'}.`,
      postReadTransform: transform,
    },
  };
}

const spaceOutLetters = (txt) => {
  const lines = String(txt || '').split(/\r?\n/);
  return lines.map((line) => {
    let out = '';
    for (const ch of line) {
      if (ch === ' ') out += '  ';
      else out += ch + ' ';
    }
    return out.trimEnd();
  }).join('\n');
};

const applyNthUpper = (text, n) => {
  let idx = 0;
  return Array.from(String(text || '')).map((ch) => {
    if (!/[a-zA-Z]/.test(ch)) return ch;
    idx += 1;
    return (idx % n === 0) ? ch.toUpperCase() : ch.toLowerCase();
  }).join('');
};

const applyLineEdits = (existingContent, edits) => {
  let lines = String(existingContent || '').split(/\r?\n/);
  if (lines.length === 1 && lines[0] === '') lines = [];
  const maxLine = Math.max(...edits.map((e) => Number(e.line || 0)));
  while (lines.length < maxLine) lines.push('');
  for (const e of edits) {
    const line = Number(e.line || 0);
    if (line >= 1) lines[line - 1] = String(e.text || '');
  }
  return lines.join('\n');
};

const escapeRegExp = (str) => String(str || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
const applyReplace = (text, spec) => {
  const re = new RegExp(escapeRegExp(spec.from), spec.caseSensitive ? 'g' : 'gi');
  return String(text || '').replace(re, String(spec.to || ''));
};

let outputText = inputText;
if (transform.type === 'space_letters') {
  outputText = spaceOutLetters(inputText);
} else if (transform.type === 'uppercase_nth') {
  const n = Number(transform.n || 0);
  if (!Number.isFinite(n) || n <= 1) {
    return { json: { action: 'error', fullPath, path: fullPath, message: 'Invalid uppercase_nth transform parameter.' } };
  }
  outputText = applyNthUpper(inputText, n);
} else if (transform.type === 'replace_text') {
  if (!String(transform.from || '').length) {
    return { json: { action: 'error', fullPath, path: fullPath, message: 'Invalid replace_text source value.' } };
  }
  outputText = applyReplace(inputText, transform);
} else if (transform.type === 'line_edit') {
  const edits = Array.isArray(transform.lineEdits) ? transform.lineEdits : [];
  if (!edits.length) {
    return { json: { action: 'error', fullPath, path: fullPath, message: 'line_edit requires at least one line edit.' } };
  }
  outputText = applyLineEdits(inputText, edits);
} else {
  return { json: { action: 'error', fullPath, path: fullPath, message: `Unsupported transform type: ${transform.type}` } };
}

return {
  json: {
    ...plan,
    action: 'write_file',
    fullPath,
    path: fullPath,
    content: String(outputText || ''),
    append: false,
    postReadTransform: transform,
    postReadTransformApplied: true,
  },
};
